create extension if not exists pgcrypto;
create table if not exists public.wishes(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mood text not null default '平靜',wish_text text not null,photo_url text,x_ratio double precision default .5,y_ratio double precision default .32,open_at timestamptz,completed boolean not null default false,completed_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.checkins(user_id uuid not null references auth.users(id) on delete cascade,checkin_date date not null,mood text not null,created_at timestamptz not null default now(),primary key(user_id,checkin_date));
create table if not exists public.profiles(user_id uuid primary key references auth.users(id) on delete cascade,zodiac text default '巨蟹座',theme text default 'midnight',scape text default 'rain',updated_at timestamptz not null default now());
alter table public.wishes add column if not exists photo_url text; alter table public.wishes add column if not exists x_ratio double precision default .5; alter table public.wishes add column if not exists y_ratio double precision default .32; alter table public.wishes add column if not exists open_at timestamptz; alter table public.wishes add column if not exists completed boolean not null default false; alter table public.wishes add column if not exists completed_at timestamptz;
alter table public.wishes enable row level security; alter table public.checkins enable row level security; alter table public.profiles enable row level security;
drop policy if exists wishes_select_own on public.wishes; drop policy if exists wishes_insert_own on public.wishes; drop policy if exists wishes_update_own on public.wishes; drop policy if exists wishes_delete_own on public.wishes;
create policy wishes_select_own on public.wishes for select to authenticated using(auth.uid()::text=user_id::text); create policy wishes_insert_own on public.wishes for insert to authenticated with check(auth.uid()::text=user_id::text); create policy wishes_update_own on public.wishes for update to authenticated using(auth.uid()::text=user_id::text) with check(auth.uid()::text=user_id::text); create policy wishes_delete_own on public.wishes for delete to authenticated using(auth.uid()::text=user_id::text);
drop policy if exists checkins_select_own on public.checkins; drop policy if exists checkins_insert_own on public.checkins; drop policy if exists checkins_update_own on public.checkins; drop policy if exists checkins_delete_own on public.checkins;
create policy checkins_select_own on public.checkins for select to authenticated using(auth.uid()::text=user_id::text); create policy checkins_insert_own on public.checkins for insert to authenticated with check(auth.uid()::text=user_id::text); create policy checkins_update_own on public.checkins for update to authenticated using(auth.uid()::text=user_id::text) with check(auth.uid()::text=user_id::text); create policy checkins_delete_own on public.checkins for delete to authenticated using(auth.uid()::text=user_id::text);
drop policy if exists profiles_select_own on public.profiles; drop policy if exists profiles_insert_own on public.profiles; drop policy if exists profiles_update_own on public.profiles;
create policy profiles_select_own on public.profiles for select to authenticated using(auth.uid()::text=user_id::text); create policy profiles_insert_own on public.profiles for insert to authenticated with check(auth.uid()::text=user_id::text); create policy profiles_update_own on public.profiles for update to authenticated using(auth.uid()::text=user_id::text) with check(auth.uid()::text=user_id::text);
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('wish-photos','wish-photos',true,2097152,array['image/jpeg','image/png','image/webp','image/gif']) on conflict(id) do update set public=true,file_size_limit=2097152,allowed_mime_types=array['image/jpeg','image/png','image/webp','image/gif'];
drop policy if exists wish_photos_upload_own on storage.objects; drop policy if exists wish_photos_public_read on storage.objects;
create policy wish_photos_upload_own on storage.objects for insert to authenticated with check(bucket_id='wish-photos' and (storage.foldername(name))[1]=auth.uid()::text); create policy wish_photos_public_read on storage.objects for select to public using(bucket_id='wish-photos');
